mapper.select:
SELECT DISTINCT seat_id
FROM sr_order
WHERE room_id = #{roomId}
  AND status IN (10, 20)
  AND deleted = 0
  AND start_time  <  #{endTime}
  AND end_time  >  #{startTime}

SELECT COUNT(1)
FROM sr_order
WHERE room_id = #{roomId}
  AND seat_id = #{seatId}
  AND status IN (10, 20)
  AND deleted = 0
  AND start_time  <  #{endTime}
  AND end_time  >  #{startTime}

SELECT COALESCE(
               SUM(
                       TIMESTAMPDIFF(
                           MINUTE,
                               GREATEST(start_time, #{startTime}),
                               LEAST(end_time, #{endTime})
                       )
               ), 0
       )
FROM sr_order
WHERE deleted = 0
  AND status = 30
  AND user_id = #{userId}
  AND end_time  >  #{startTime}
  AND start_time  <  #{endTime}

SELECT COUNT(1)
FROM sr_order
WHERE deleted = 0
  AND status = 30
  AND user_id = #{userId}
  AND end_time  >  #{startTime}
  AND start_time  <  #{endTime}

SELECT COUNT(1) + 1
FROM (
         SELECT user_id,
                SUM(
                        TIMESTAMPDIFF(
                            MINUTE,
                                GREATEST(start_time, #{startTime}),
                                LEAST(end_time, #{endTime})
                        )
                ) AS studyMinutes
         FROM sr_order
         WHERE deleted = 0
           AND status = 30
           AND end_time  >  #{startTime}
           AND start_time  <  #{endTime}
         GROUP BY user_id
         HAVING studyMinutes  >  #{myMinutes}
             OR (studyMinutes = #{myMinutes} AND user_id  <  #{userId})
     ) t
